import{_ as a,o as s,c as i,ag as l}from"./chunks/framework.Dn0B0GT3.js";const u=JSON.parse('{"title":"Tailscale Integration","description":"Expose ShellPort publicly using Tailscale serve or funnel","frontmatter":{"title":"Tailscale Integration","description":"Expose ShellPort publicly using Tailscale serve or funnel"},"headers":[],"relativePath":"guides/tailscale.md","filePath":"guides/tailscale.md"}'),t={name:"guides/tailscale.md"};function n(r,e,o,h,c,p){return s(),i("div",null,[...e[0]||(e[0]=[l(`<h1 id="tailscale-integration" tabindex="-1">Tailscale Integration <a class="header-anchor" href="#tailscale-integration" aria-label="Permalink to &quot;Tailscale Integration&quot;">​</a></h1><p>ShellPort has built-in support for <a href="https://tailscale.com/" target="_blank" rel="noreferrer">Tailscale</a> — the fastest way to securely share your terminal over the internet. With a single flag, you can expose your server via your Tailscale network or even the public internet.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li><a href="https://tailscale.com/download" target="_blank" rel="noreferrer">Tailscale</a> installed and running on the server</li><li>A Tailscale account (free tier works)</li><li>The Tailscale CLI must be in your PATH</li></ul><p>Verify Tailscale is installed and authenticated:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p>You should see your Tailscale identity and current status.</p><h2 id="two-integration-modes" tabindex="-1">Two Integration Modes <a class="header-anchor" href="#two-integration-modes" aria-label="Permalink to &quot;Two Integration Modes&quot;">​</a></h2><h3 id="tailscale-serve" tabindex="-1">Tailscale Serve <a class="header-anchor" href="#tailscale-serve" aria-label="Permalink to &quot;Tailscale Serve&quot;">​</a></h3><p><strong>Purpose:</strong> Expose ShellPort to your Tailscale network only.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span></span></code></pre></div><p>This makes ShellPort accessible to:</p><ul><li>✅ Your own devices on Tailscale</li><li>✅ Anyone you share your Tailscale network with</li><li>❌ The general public internet</li></ul><p><strong>Use case:</strong> Perfect for personal use across your own devices or sharing with trusted individuals on your Tailscale tailnet.</p><h3 id="tailscale-funnel" tabindex="-1">Tailscale Funnel <a class="header-anchor" href="#tailscale-funnel" aria-label="Permalink to &quot;Tailscale Funnel&quot;">​</a></h3><p><strong>Purpose:</strong> Expose ShellPort to the public internet via Tailscale Funnel.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> funnel</span></span></code></pre></div><p>This makes ShellPort accessible to:</p><ul><li>✅ Anyone with the URL</li><li>✅ The general public internet</li><li>⚠️ No built-in authentication (use <code>--no-totp</code> cautiously or combine with Tailscale ACLs)</li></ul><p><strong>Use case:</strong> When you need to share your terminal with someone outside your Tailscale network, or for demos and quick collaboration.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>When using <code>--tailscale funnel</code>, your server is publicly accessible. Always use <code>--secret</code> or <code>--no-secret</code> (with TOTP) for authentication. Consider using Tailscale ACLs to restrict access.</p></div><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>When you use <code>--tailscale serve</code> or <code>--tailscale funnel</code>, ShellPort:</p><ol><li>Starts the HTTP/WebSocket server on <code>localhost:7681</code></li><li>Uses <code>tailscale serve</code> or <code>tailscale funnel</code> to create the HTTPS reverse proxy</li><li>Prints the public URL for easy access</li></ol><h3 id="example-output" tabindex="-1">Example Output <a class="header-anchor" href="#example-output" aria-label="Permalink to &quot;Example Output&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ shellport server --tailscale serve</span></span>
<span class="line"><span>[ShellPort] 🌐 Starting server on localhost:7681</span></span>
<span class="line"><span>[ShellPort] 🔐 Tailscale serve enabled</span></span>
<span class="line"><span>[ShellPort] 🔗 Shareable URL: https://your-device.tail1234.ts.net/shellport/</span></span>
<span class="line"><span>[ShellPort] 🌐 Open in browser: https://your-device.tail1234.ts.net/shellport/#your-secret</span></span></code></pre></div><p>For funnel mode:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ shellport server --tailscale funnel</span></span>
<span class="line"><span>[ShellPort] 🌐 Starting server on localhost:7681</span></span>
<span class="line"><span>[ShellPort] 🔐 Tailscale funnel enabled</span></span>
<span class="line"><span>[ShellPort] 🔗 Public URL: https://your-device.example.com/shellport/</span></span>
<span class="line"><span>[ShellPort] 🌐 Open in browser: https://your-device.example.com/shellport/#your-secret</span></span></code></pre></div><h2 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th><code>serve</code></th><th><code>funnel</code></th></tr></thead><tbody><tr><td>Accessible from Tailscale</td><td>✅</td><td>✅</td></tr><tr><td>Accessible from internet</td><td>❌</td><td>✅</td></tr><tr><td>HTTPS provided</td><td>✅</td><td>✅</td></tr><tr><td>Requires domain</td><td>❌</td><td>⚠️</td></tr><tr><td>Auth by ShellPort</td><td>✅</td><td>✅</td></tr></tbody></table><h2 id="recommended-usage" tabindex="-1">Recommended Usage <a class="header-anchor" href="#recommended-usage" aria-label="Permalink to &quot;Recommended Usage&quot;">​</a></h2><h3 id="personal-use-serve" tabindex="-1">Personal Use (Serve) <a class="header-anchor" href="#personal-use-serve" aria-label="Permalink to &quot;Personal Use (Serve)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Start with full security via Tailscale serve</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Or with TOTP only (Tailscale encrypts the connection)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-secret</span></span></code></pre></div><h3 id="public-sharing-funnel" tabindex="-1">Public Sharing (Funnel) <a class="header-anchor" href="#public-sharing-funnel" aria-label="Permalink to &quot;Public Sharing (Funnel)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># With encryption + TOTP</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> funnel</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># TOTP only (Tailscale encrypts, you verify identity)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> funnel</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-secret</span></span></code></pre></div><h2 id="tailscale-acls" tabindex="-1">Tailscale ACLs <a class="header-anchor" href="#tailscale-acls" aria-label="Permalink to &quot;Tailscale ACLs&quot;">​</a></h2><p>For <code>serve</code> mode, you can use Tailscale Access Control Lists (ACLs) to control who can access your server. Edit your Tailscale ACL policy to allow specific users or groups to access the ShellPort service.</p><p>Example ACL policy fragment:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;acls&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;action&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;accept&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;src&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;group:trusted&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;dst&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;*:*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="security-considerations" tabindex="-1">Security Considerations <a class="header-anchor" href="#security-considerations" aria-label="Permalink to &quot;Security Considerations&quot;">​</a></h2><h3 id="with-tailscale-serve" tabindex="-1">With <code>--tailscale serve</code> <a class="header-anchor" href="#with-tailscale-serve" aria-label="Permalink to &quot;With \`--tailscale serve\`&quot;">​</a></h3><ul><li>Access is limited to your Tailscale network</li><li>Tailscale provides the encryption layer</li><li>Combine with <code>--no-secret --no-totp</code> for TOTP-only auth (Tailscale encrypts)</li></ul><h3 id="with-tailscale-funnel" tabindex="-1">With <code>--tailscale funnel</code> <a class="header-anchor" href="#with-tailscale-funnel" aria-label="Permalink to &quot;With \`--tailscale funnel\`&quot;">​</a></h3><ul><li>Server is publicly accessible</li><li>Always use authentication: <ul><li><code>--secret</code> for encryption-based auth</li><li><code>--no-secret</code> with TOTP for 2FA</li></ul></li><li>Consider Tailscale ACLs to restrict by source IP</li><li>Funnel binds to port 443 automatically</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="tailscale-command-not-found" tabindex="-1">&quot;tailscale: command not found&quot; <a class="header-anchor" href="#tailscale-command-not-found" aria-label="Permalink to &quot;&quot;tailscale: command not found&quot;&quot;">​</a></h3><p>Ensure Tailscale is installed. Download from <a href="https://tailscale.com/download" target="_blank" rel="noreferrer">tailscale.com/download</a>.</p><h3 id="tailscale-serve-requires-being-enabled" tabindex="-1">&quot;tailscale serve requires being enabled&quot; <a class="header-anchor" href="#tailscale-serve-requires-being-enabled" aria-label="Permalink to &quot;&quot;tailscale serve requires being enabled&quot;&quot;">​</a></h3><p>Run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bg</span></span></code></pre></div><p>Or enable it in the Tailscale admin console.</p><h3 id="funnel-requires-a-domain" tabindex="-1">&quot;funnel requires a domain&quot; <a class="header-anchor" href="#funnel-requires-a-domain" aria-label="Permalink to &quot;&quot;funnel requires a domain&quot;&quot;">​</a></h3><p>Funnel needs either:</p><ul><li>A Tailscale Funnel domain (e.g., <code>device.name.ts.net</code>)</li><li>A custom domain configured in Tailscale</li></ul><p>For simple use cases, <code>serve</code> is recommended as it works with Tailscale&#39;s built-in DNS.</p><h2 id="further-reading" tabindex="-1">Further Reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further Reading&quot;">​</a></h2><ul><li><a href="https://tailscale.com/kb/1312/tailscale-serve" target="_blank" rel="noreferrer">Tailscale Serve documentation</a></li><li><a href="https://tailscale.com/kb/1224/tailscale-funnel" target="_blank" rel="noreferrer">Tailscale Funnel documentation</a></li><li><a href="https://tailscale.com/kb/1018/acls" target="_blank" rel="noreferrer">Tailscale ACLs</a></li></ul>`,57)])])}const k=a(t,[["render",n]]);export{u as __pageData,k as default};
